architect_plan:
{
  "summary": "Dwa blokujące problemy uniemożliwiają działanie docker-compose up: (1) `drizzle-kit` jest w devDependencies, więc nie jest instalowany w warstwie runner Dockerfile'a — CMD `npx drizzle-kit push` kończy się błędem; (2) `depends_on: db` czeka tylko na uruchomienie kontenera, nie na gotowość PostgreSQL — migracja odpala się zanim baza zaakceptuje połączenia. Naprawa: przeniesienie `drizzle-kit` do dependencies + dodanie healthcheck z `condition: service_healthy`.",
  "plan": [
    {
      "step": 1,
      "title": "Healthcheck db + condition w app.depends_on",
      "description": "W serwisie `db` dodać blok `healthcheck` używający `pg_isready`, który sprawdza gotowość PostgreSQL (interval 5s, timeout 5s, retries 5). W serwisie `app` zmienić `depends_on` z prostej listy na mapę obiektów z `condition: service_healthy`, żeby app startował dopiero gdy PostgreSQL faktycznie akceptuje połączenia.",
      "files_affected": [
        "docker-compose.yml"
      ],
      "type": "MODIFY"
    },
    {
      "step": 2,
      "title": "Przenieś drizzle-kit do dependencies",
      "description": "Przenieść wpis `drizzle-kit` z bloku `devDependencies` do bloku `dependencies` w package.json. W Dockerfile runner stage uruchomiane jest `npm ci --omit=dev`, więc devDependencies nie są instalowane — `npx drizzle-kit push` w CMD nie znajdzie pakietu i zwróci błąd. Po przeniesieniu drizzle-kit będzie dostępny w warstwie produkcyjnej.",
      "files_affected": [
        "package.json"
      ],
      "type": "MODIFY"
    }
  ],
  "acceptance_criteria": [
    {
      "id": "c1",
      "description": "Serwis `db` w docker-compose.yml posiada blok `healthcheck` z kluczami `test`, `interval`, `timeout`, `retries`; `test` wywołuje `pg_isready`",
      "how_to_verify": "Odczytać docker-compose.yml, sprawdzić czy services.db.healthcheck.test zawiera `pg_isready`"
    },
    {
      "id": "c2",
      "description": "Serwis `app` w docker-compose.yml ma `depends_on.db.condition: service_healthy`",
      "how_to_verify": "Odczytać docker-compose.yml, sprawdzić czy services.app.depends_on.db.condition == 'service_healthy'"
    },
    {
      "id": "c3",
      "description": "`drizzle-kit` widnieje w sekcji `dependencies` (nie tylko `devDependencies`) w package.json",
      "how_to_verify": "Odczytać package.json, sprawdzić czy klucz `drizzle-kit` istnieje w bloku `dependencies`"
    },
    {
      "id": "c4",
      "description": "`drizzle-kit` NIE istnieje już w sekcji `devDependencies` w package.json",
      "how_to_verify": "Odczytać package.json, sprawdzić że klucz `drizzle-kit` nie istnieje w bloku `devDependencies`"
    }
  ],
  "risks": [
    "Przeniesienie drizzle-kit do dependencies zwiększa rozmiar obrazu Docker i instalację produkcyjną — drizzle-kit jest ciężki (~40MB), ale nie ma lepszej alternatywy bez przepisania CMD na skrypt z drizzle-orm",
    "Jeśli PostgreSQL nie uruchomi się w czasie 5 retries × 5s = 25s (np. bardzo wolna maszyna), app nie wystartuje — można podnieść `retries` do 10 lub `start_period` dodać dla bezpieczeństwa"
  ]
}
